mapper.select:
SELECT uv.id, uv.user_id, uv.user_account, uv.vehicle_id, uv.imei, uv.bind_status, vbs.scheme_id, bs.scheme_name, uv.create_time, uv.update_time FROM user_vehicle uv LEFT JOIN vehicle_battery_scheme vbs ON uv.imei = vbs.imei AND vbs.deleted = 0 LEFT JOIN battery_scheme bs ON vbs.scheme_id = bs.id AND bs.deleted = 0 WHERE uv.deleted = 0
AND uv.user_account LIKE CONCAT('%', #{userAccount}, '%')
AND uv.imei = #{imei}
AND uv.bind_status = #{bindStatus}
ORDER BY uv.id DESC
